import{_ as a,o as e,c as r,a2 as d}from"./chunks/framework.e-meDy3u.js";const q=JSON.parse('{"title":"Q3 · 只用飞书 + AI + 脚本，7 天交付什么？","description":"","frontmatter":{},"headers":[],"relativePath":"q3.md","filePath":"q3.md"}'),o={name:"q3.md"};function p(l,t,s,i,h,n){return e(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="q3-·-只用飞书-ai-脚本-7-天交付什么" tabindex="-1">Q3 · 只用飞书 + AI + 脚本，7 天交付什么？ <a class="header-anchor" href="#q3-·-只用飞书-ai-脚本-7-天交付什么" aria-label="Permalink to &quot;Q3 · 只用飞书 + AI + 脚本，7 天交付什么？&quot;">​</a></h1><p class="hqq-lede">答歪的方式只有一个：端出一套新东西。答对的方式是——七天交付物就是 Q2 那个第一版，我只是把它摊成施工排期。</p><h2 id="结论" tabindex="-1">结论 <a class="header-anchor" href="#结论" aria-label="Permalink to &quot;结论&quot;">​</a></h2><p><strong>七天不建平台，建一个能用的爆款素材库</strong>：装着真实赢家、AI 打好标签、告诉自家店这轮投哪条、收得回数据还能自动排名出日报。</p><p>全部就是 Q2 的两张飞书表，加上施工顺序。没有新工具，没有新概念。</p><hr><h2 id="七天排期" tabindex="-1">七天排期 <a class="header-anchor" href="#七天排期" aria-label="Permalink to &quot;七天排期&quot;">​</a></h2><p>每天产出什么看得见的东西，不按每天干什么活排。</p><table tabindex="0"><thead><tr><th>时间</th><th>产出</th></tr></thead><tbody><tr><td>Day 1</td><td>搭两张飞书表 + 把历史爆款素材灌进库（库开局不空）+ 提交飞书写入权限审批</td></tr><tr><td>Day 2</td><td>AI 捷径给素材打标签：卖点、人群、场景，机器填人校对</td></tr><tr><td>Day 3</td><td>分发回收表跑通 + &quot;这轮用哪条&quot;的投放视图，把素材真正用到自家私店</td></tr><tr><td>Day 4</td><td>脚本写回（权限到位的话）：把 Excel 导出的回收数据批量写进表</td></tr><tr><td>Day 5</td><td>自动排名视图 + 日报，库开始自己排名指导追投</td></tr><tr><td>Day 6</td><td>端到端跑一遍真实数据，哪里断了修哪里</td></tr><tr><td>Day 7</td><td>交付演示 + 使用 SOP</td></tr></tbody></table><hr><h2 id="王牌-这七天正好是技术面那个原型该接的下一步" tabindex="-1">王牌：这七天正好是技术面那个原型该接的下一步 <a class="header-anchor" href="#王牌-这七天正好是技术面那个原型该接的下一步" aria-label="Permalink to &quot;王牌：这七天正好是技术面那个原型该接的下一步&quot;">​</a></h2><p>技术面交的原型（<code>ai-eco-workflow</code>）干的是生产端：锁产品事实包 → 设实验变量 → 生成主图和详情页候选，带合规护栏。</p><p>它的下一步，我当时就规划好了，是把生成结果写进飞书素材库，让造出来的候选有地方沉淀、排名、复用。</p><p>所以这七天的交付，就是把那个&quot;下一步&quot;做出来：接上原型的出料口，在自家店把&quot;生产→库→投放→回收&quot;跑成闭环。</p><p>两段关系钉死：<strong>技术面原型 = 生产端（素材怎么造）；这周的库 = 出料口（造出来和赢过的素材存哪、怎么排名）。</strong></p><hr><h2 id="诚实边界" tabindex="-1">诚实边界 <a class="header-anchor" href="#诚实边界" aria-label="Permalink to &quot;诚实边界&quot;">​</a></h2><p>有一个我控制不了的点，先说清楚：脚本自动写回依赖飞书写入权限审批（企业自建应用 bitable:app 权限），那个时间不在我手上。审批慢就第七天先手动占坑，脚本第八九天补。</p><p>其余——两张表、灌库、AI 打标签、分发、排名视图——都是我一周内确定能交出来的，不依赖任何外部审批。</p><p>原型目前是演示阶段，不是生产级。它证明的是这条链能跑通，不是明天就上量。我不会把这个说成&quot;明天上生产&quot;，但它也不是 PPT。</p><hr><details class="details custom-block"><summary>📱 微信简版 — 可直接发送</summary><p>第三题——七天用飞书加 AI 加脚本交付什么。</p><p>七天我不建平台，建一个能用的爆款素材库。就是上一版讲的第一版：两张飞书表，第一天就灌进真实爆款、库开局不空，中间用 AI 标好卖点人群、把素材用到自家店投放，后几天接脚本把回收数据写回、出排名日报，最后跑通闭环、演示交接。</p><p>正好这也是我技术面那个生成原型该接的下一步——把生成结果接进飞书库。不是新方案，是接着上次的活往下做。</p><p>一个我控不了的点先讲：脚本自动写回要等飞书应用权限审批，时间不在我手上。审批慢就第七天先手动录、脚本第八九天补。其余我一周内确定交得出。</p></details>',22)])])}const u=a(o,[["render",p]]);export{q as __pageData,u as default};
